import { syntaxTree } from '@codemirror/language';
import { RangeSetBuilder } from '@codemirror/state';
import { ViewPlugin } from '@codemirror/view';
import type {
  Decoration,
  DecorationSet,
  EditorView,
  ViewUpdate,
} from '@codemirror/view';

import { variableMark } from './decoration-marks.js';

/**
 * Create a range set with decorations for all variables.
 * @internal
 */
export function createFilterVariableDecorations(view: EditorView) {
  const builder = new RangeSetBuilder<Decoration>();

  for (const { from, to } of view.visibleRanges) {
    const tree = syntaxTree(view.state);
    tree.iterate({
      from,
      to,
      enter: (node) => {
        if (node.name === 'Variable') {
          const { from: valueFrom, to: valueTo } = node;
          builder.add(valueFrom, valueTo, variableMark);
        }
      },
    });
  }

  return builder.finish();
}

/**
 * View plugin to wrap all filter variables in spans.
 * @internal
 */
export const FilterVariableDecorationPlugin = ViewPlugin.fromClass(
  class {
    decorations: DecorationSet;

    constructor(view: EditorView) {
      this.decorations = createFilterVariableDecorations(view);
    }

    update(update: ViewUpdate) {
      if (update.docChanged) {
        this.decorations = createFilterVariableDecorations(update.view);
      }
    }
  },
  {
    decorations: (view) => view.decorations,
  },
);
